import React, { useEffect, useState } from 'react';
import toast from 'react-hot-toast';
import VideoTable from '../components/VideoTable';
import { fetchDashboardKpis, triggerScrape } from '../services/api';

function fmtInt(n) {
  if (n == null || Number.isNaN(Number(n))) return '—';
  return Number(n).toLocaleString();
}

function fmtPct(p) {
  if (p == null || p === '') return '—';
  const n = Number(p);
  if (Number.isNaN(n)) return '—';
  const sign = n > 0 ? '+' : '';
  return `${sign}${n}%`;
}

function fmtMoney(n) {
  if (n == null || Number.isNaN(Number(n))) return '—';
  return Number(n).toLocaleString(undefined, {
    minimumFractionDigits: 2,
    maximumFractionDigits: 4,
  });
}

function GrowthLine({ label, pct }) {
  const p = pct == null || pct === '' ? null : Number(pct);
  const up = p != null && !Number.isNaN(p) && p >= 0;
  return (
    <p className="kpi-card-growth">
      <span className="kpi-card-growth-label">{label}</span>
      {p == null || Number.isNaN(p) ? (
        <span className="kpi-card-growth-muted">—</span>
      ) : (
        <span className={up ? 'kpi-card-growth-up' : 'kpi-card-growth-down'}>
          {up ? '↑' : '↓'} {Math.abs(p)}% vs last run
        </span>
      )}
    </p>
  );
}

export default function Dashboard() {
  const [kpis, setKpis] = useState(null);
  const [loadingKpis, setLoadingKpis] = useState(true);
  const [scraping, setScraping] = useState(false);

  const loadKpis = () => {
    setLoadingKpis(true);
    fetchDashboardKpis()
      .then((res) => setKpis(res.data))
      .catch(console.error)
      .finally(() => setLoadingKpis(false));
  };

  useEffect(() => {
    loadKpis();
    const onVideosUpdated = () => loadKpis();
    window.addEventListener('videos-updated', onVideosUpdated);
    return () => window.removeEventListener('videos-updated', onVideosUpdated);
  }, []);

  const handleScrapeNow = async () => {
    setScraping(true);
    try {
      const res = await triggerScrape();
      toast.success(`Scraped ${res.data.scraped} videos`);
      setTimeout(() => {
        loadKpis();
        window.dispatchEvent(new CustomEvent('videos-updated', { detail: {} }));
      }, 800);
    } catch (err) {
      toast.error(err.response?.data?.error || 'Scrape failed');
    } finally {
      setScraping(false);
    }
  };

  const port = kpis?.portfolio;
  const pct = port?.pctChange;

  return (
    <div className="page-dashboard">
      <div className="page-header page-header--hero">
        <div className="page-header-titles">
          <h1>Dashboard</h1>
          <p className="page-subtitle">
            Portfolio KPIs vs your last scrape run, plus new videos by week.
          </p>
        </div>
      </div>

      <section className="dashboard-kpi-section" aria-label="Key metrics">
        {loadingKpis ? (
          <div className="dashboard-kpi-grid dashboard-kpi-grid--loading">
            {[1, 2, 3, 4, 5, 6, 7, 8, 9].map((i) => (
              <div key={i} className="kpi-card kpi-card--skeleton" />
            ))}
          </div>
        ) : (
          <div className="dashboard-kpi-grid">
            <article className="kpi-card">
              <h3 className="kpi-card-title">Total videos</h3>
              <p className="kpi-card-value">{fmtInt(kpis?.totalVideosActive)}</p>
              <p className="kpi-card-sub">
                Last 7d vs prior 7d (new):{' '}
                <strong>{fmtInt(kpis?.videosNewLast7d)}</strong> vs{' '}
                <strong>{fmtInt(kpis?.videosNewPrior7d)}</strong>
              </p>
            </article>

            <article className="kpi-card">
              <h3 className="kpi-card-title">Total views</h3>
              <p className="kpi-card-value">{fmtInt(port?.latest?.views)}</p>
              <GrowthLine label="Growth" pct={pct?.views} />
            </article>

            <article className="kpi-card">
              <h3 className="kpi-card-title">Likes</h3>
              <p className="kpi-card-value">{fmtInt(port?.latest?.likes)}</p>
              <GrowthLine label="Growth" pct={pct?.likes} />
            </article>

            <article className="kpi-card">
              <h3 className="kpi-card-title">Comments</h3>
              <p className="kpi-card-value">{fmtInt(port?.latest?.comments)}</p>
              <GrowthLine label="Growth" pct={pct?.comments} />
            </article>

            <article className="kpi-card">
              <h3 className="kpi-card-title">Shares</h3>
              <p className="kpi-card-value">{fmtInt(port?.latest?.shares)}</p>
              <GrowthLine label="Growth" pct={pct?.shares} />
            </article>

            <article className="kpi-card">
              <h3 className="kpi-card-title">Saves</h3>
              <p className="kpi-card-value">{fmtInt(port?.latest?.saves)}</p>
              <GrowthLine label="Growth" pct={pct?.saves} />
            </article>

            <article className="kpi-card">
              <h3 className="kpi-card-title">Avg engagement</h3>
              <p className="kpi-card-value">
                {kpis?.avgEngagementPct != null ? `${kpis.avgEngagementPct}%` : '—'}
              </p>
              <p className="kpi-card-sub">
                (Likes + shares + saves + comments) ÷ views, latest run totals
              </p>
            </article>

            <article className="kpi-card">
              <h3 className="kpi-card-title">Pay per view</h3>
              <p className="kpi-card-value">
                {kpis?.payPerView != null ? `$${fmtMoney(kpis.payPerView)}` : '—'}
              </p>
              <p className="kpi-card-sub">
                Sum of Total Cost on active videos ÷ latest portfolio views
              </p>
            </article>

            <article className="kpi-card">
              <h3 className="kpi-card-title">Transactions</h3>
              <p className="kpi-card-value">{fmtInt(kpis?.transactionsTotal)}</p>
              <p className="kpi-card-sub">
                Sum of Sales on tracked videos
                {kpis?.transactionsVideos != null && kpis.transactionsVideos > 0
                  ? ` · ${kpis.transactionsVideos} video${kpis.transactionsVideos !== 1 ? 's' : ''} with sales`
                  : ''}
              </p>
            </article>
          </div>
        )}

        {kpis?.portfolio && kpis.portfolio.videosCompared === 0 && kpis.totalVideosActive > 0 && (
          <p className="dashboard-kpi-footnote muted-caption">
            Run comparison (growth %) appears after each active video has at least two scrapes.
          </p>
        )}
      </section>

      <section className="dashboard-overview-section" aria-labelledby="dashboard-overview-heading">
        <div className="dashboard-overview-head">
          <div>
            <h2 id="dashboard-overview-heading" className="dashboard-section-title">
              Overview
            </h2>
            <p className="page-subtitle dashboard-overview-lead">
              Scrape fresh metrics and review per-video performance (Δ vs previous run).
            </p>
          </div>
          <button
            type="button"
            className="btn btn-primary"
            disabled={scraping}
            onClick={handleScrapeNow}
          >
            {scraping ? 'Scraping…' : 'Scrape now'}
          </button>
        </div>

        <VideoTable />
      </section>
    </div>
  );
}
